package com.codelens.entity;import jakarta.persistence.*;import lombok.*;import java.time.*;@Entity @Table(name="pull_requests") @Getter @Setter @NoArgsConstructor public class PullRequestEntity{@Id @GeneratedValue(strategy=GenerationType.IDENTITY) Long id; @ManyToOne(optional=false) RepositoryEntity repository; Integer number; String title; String author; @Column(length=1024) String diffUrl; @Column(length=1024) String htmlUrl; String state; String status="RECEIVED"; @Column(length=4000) String summary; @Column(length=4000) String filesChanged; Instant createdAt=Instant.now(); Instant updatedAt=Instant.now();}
